    try {
      await startProfiling('main');

      const worker = new Worker(path.join(__dirname, 'fibonacci.cjs'), {
        env: process.env
      });

      worker.on('error', (err) => {
        console.error('Worker error:', err);
      });

      worker.on('exit', async (code) => {
        if (code !== 0) {
          console.error('Worker exited with code', code);
        }
